CREATE TABLE IF NOT EXISTS setup_episodes (id INTEGER PRIMARY KEY AUTOINCREMENT, episode_key TEXT NOT NULL UNIQUE, source TEXT NOT NULL, symbol TEXT NOT NULL, t0_ms INTEGER NOT NULL, trading_day TEXT NOT NULL, session TEXT NOT NULL, tod_bucket TEXT, asset_class TEXT NOT NULL DEFAULT 'stock', direction TEXT, regime_label TEXT, regime_model_version INTEGER, liquidity_tier TEXT, validity_tier TEXT, price_structure_json TEXT, momentum_json TEXT, volume_json TEXT, volatility_json TEXT, regime_json TEXT, sector_json TEXT, breadth_json TEXT, options_context_json TEXT, catalyst_json TEXT, liquidity_json TEXT, data_quality_json TEXT, missing_json TEXT, gate_results_json TEXT, feature_schema_version INTEGER NOT NULL, max_feature_as_of_ms INTEGER NOT NULL, provenance_json TEXT, created_at_ms INTEGER NOT NULL);
CREATE TABLE IF NOT EXISTS episode_labels (id INTEGER PRIMARY KEY AUTOINCREMENT, episode_key TEXT NOT NULL, horizon TEXT NOT NULL, target_kind TEXT NOT NULL, outcome_kind TEXT NOT NULL, return_pct REAL, mfe_pct REAL, mae_pct REAL, target_before_stop TEXT, time_to_target_ms INTEGER, time_to_invalidation_ms INTEGER, realized_vol REAL, gap_pct REAL, gap_filled INTEGER, model_assumptions_json TEXT, label_as_of_ms INTEGER NOT NULL, computed_at_ms INTEGER NOT NULL, UNIQUE(episode_key, horizon, target_kind));
CREATE TABLE IF NOT EXISTS replay_runs (run_id TEXT PRIMARY KEY, experiment_id TEXT NOT NULL, asset_class TEXT NOT NULL, symbols_json TEXT NOT NULL, date_from TEXT NOT NULL, date_to TEXT NOT NULL, timespan TEXT NOT NULL, strategy_version INTEGER NOT NULL, config_json TEXT, status TEXT NOT NULL, checkpoint_json TEXT, provider_calls INTEGER NOT NULL DEFAULT 0, provider_call_budget INTEGER NOT NULL DEFAULT 0, provider_limitations TEXT, error TEXT, created_at_ms INTEGER NOT NULL, updated_at_ms INTEGER NOT NULL, provider_calls_attempted INTEGER NOT NULL DEFAULT 0, symbols_with_data INTEGER NOT NULL DEFAULT 0, per_symbol_json TEXT, episodes_captured INTEGER NOT NULL DEFAULT 0, labels_captured INTEGER NOT NULL DEFAULT 0, symbols_total INTEGER NOT NULL DEFAULT 0, symbols_done INTEGER NOT NULL DEFAULT 0, chunks_completed INTEGER NOT NULL DEFAULT 0, current_symbol TEXT, cancel_requested INTEGER NOT NULL DEFAULT 0, started_at_ms INTEGER, lease_owner TEXT, lease_until_ms INTEGER, heartbeat_ms INTEGER);
